module asyn_fifo #(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)(
    input wclk,
    input rclk,
    input rstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata,
    output wfull,
    output rempty,
    output [WIDTH-1:0] rdata
);

localparam ADDR_WIDTH = $clog2(DEPTH);

// Dual-port RAM instance
reg [WIDTH-1:0] ram [0:DEPTH-1];
reg [ADDR_WIDTH-1:0] waddr, raddr;

// Write port
always @(posedge wclk or negedge rstn) begin
    if (!rstn) begin
        waddr <= 0;
    end else if (winc && !wfull) begin
        ram[waddr] <= wdata;
        waddr <= waddr + 1'b1;
    end
end

// Read port
always @(posedge rclk or negedge rstn) begin
    if (!rstn) begin
        raddr <= 0;
    end else if (rinc && !rempty) begin
        raddr <= raddr + 1'b1;
    end
end

// Full and empty flags
assign wfull = (waddr == (raddr + 1'b1)) ? 1'b1 : 1'b0;
assign rempty = (waddr == raddr) ? 1'b1 : 1'b0;
assign rdata = ram[raddr];

endmodule
